const CACHE_NAME="global-tech-cache-v1",urlsToCache=["./","./index.html","./about.html","./courses.html","./admissions.html","./faculty.html","./gallery.html","./contact.html","./style.css","./script.js"];self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE_NAME).then(e=>(console.log("Opened cache"),e.addAll(urlsToCache))))}),self.addEventListener("activate",e=>{const t=[CACHE_NAME];e.waitUntil(caches.keys().then(e=>Promise.all(e.map(e=>{if(-1===t.indexOf(e))return caches.delete(e)}))))}),self.addEventListener("fetch",e=>{e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request)))});